import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        while (sc.hasNextInt()) {
            int d = sc.nextInt();
            int n = sc.nextInt();
            int h = sc.nextInt();
            int v = sc.nextInt();
            int vh = sc.nextInt();
            if (d == 0) break;
            double t1 = (double)d / v;
            double t2 = (double)d / vh;
            double t3 = (double)(d * (n - h)) / (double)(v * n) + (double)(d * h) / (double)(vh * n);
            double t = t1 > t2 ? t1 : t2;
            t = t > t3 ? t : t3;
            System.out.printf("%.0f/%.0f\n", t * 5, 5);
        }
    }
}

