while (idx < lines.length) {
    const [d, n, h, v, vh] = lines[idx].split(' ').map(Number);
    if (d === 0) break;
    const t1 = d / v;
    const t2 = d / vh;
    const t3 = (d * (n - h)) / (v * n) + (d * h) / (vh * n);
    const t = Math.max(t1, t2, t3);
    console.log(`${Math.floor(t * 5)}/${5}`);
    idx++;
}
